input = sys.stdin.read
data = input().split()

index = 0
t = int(data[index])
index += 1

for _ in range(t):
    n = int(data[index])
    index += 1
    a = []
    for j in range(n):
        a.append(int(data[index]))
        index += 1

    height = 1
    consec = 0
    dead = False
    for i in range(n):
        if a[i] == 0:
            consec += 1
            if consec >= 2:
                dead = True
        else:
            consec = 0
            if i == 0 or a[i-1] == 0:
                height += 1
            else:
                height += 5
    if dead:
        print(-1)
    else:
        print(height)

