import sys

input = sys.stdin.read
data = input().split()

index = 0
N = int(data[index])
index += 1
A = [int(data[i]) for i in range(index, index + N)]

left_len = 1
for i in range(1, N):
    if A[i] > A[i - 1]:
        left_len += 1
    else:
        break

right_len = 1
for i in range(N - 2, -1, -1):
    if A[i] > A[i + 1]:
        right_len += 1
    else:
        break

if (left_len % 2 == 0) and (right_len % 2 == 0):
    print("Bob")
else:
    print("Alice")

