import sys
from math import gcd

input = sys.stdin.read
data = input().split()

index = 0
t = int(data[index])
index += 1

for _ in range(t):
    n = int(data[index])
    index += 1
    a = [int(data[index + j]) for j in range(n)]
    index += n

    cnt = [0] * 30
    for val in a:
        for b in range(30):
            if val & (1 << b):
                cnt[b] += 1

    g = 0
    for c in cnt:
        g = gcd(g, c)

    if g == 0:
        ans = list(range(1, n + 1))
    else:
        divs = []
        i = 1
        while i * i <= g:
            if g % i == 0:
                divs.append(i)
                if i != g // i:
                    divs.append(g // i)
            i += 1
        ans = sorted(divs)

    print(' '.join(map(str, ans)))

