input = sys.stdin.read
data = input().split()

index = 0
t = int(data[index])
index += 1

for _ in range(t):
    x1 = int(data[index])
    p1 = int(data[index + 1])
    index += 2
    x2 = int(data[index])
    p2 = int(data[index + 1])
    index += 2

    d1 = len(str(x1))
    d2 = len(str(x2))
    l1 = d1 + p1
    l2 = d2 + p2

    if l1 > l2:
        print('>')
    elif l1 < l2:
        print('<')
    else:
        k = p2 - p1
        if k >= 0:
            y = x2 * (10 ** k)
            if x1 > y:
                print('>')
            elif x1 < y:
                print('<')
            else:
                print('=')
        else:
            k = -k
            y = x1 * (10 ** k)
            if y > x2:
                print('>')
            elif y < x2:
                print('<')
            else:
                print('=')

